import CohortDetails from './components/CohortDetails';

const cohorts = [
  { id: 1, cohortName: 'Cohort Alpha', trainer: 'John Smith', startDate: '2024-01-10', endDate: '2024-04-10', status: 'completed' },
  { id: 2, cohortName: 'Cohort Beta', trainer: 'Jane Doe', startDate: '2024-06-01', endDate: '2024-09-01', status: 'ongoing' },
  { id: 3, cohortName: 'Cohort Gamma', trainer: 'Bob Lee', startDate: '2024-09-15', endDate: '2024-12-15', status: 'ongoing' },
  { id: 4, cohortName: 'Cohort Delta', trainer: 'Alice Brown', startDate: '2023-03-01', endDate: '2023-06-01', status: 'completed' },
];

function App() {
  return (
    <div>
      {cohorts.map(cohort => (
        <CohortDetails key={cohort.id} cohort={cohort} />
      ))}
    </div>
  );
}

export default App;
